// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/cryptography/MerkleProof.sol";

/**
 * @title FinCoreDividends
 * @dev Contrato de distribucion de dividendos usando Merkle Trees.
 * Permite distribuciones eficientes a miles de holders con una sola transaccion.
 */
contract FinCoreDividends is AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    bytes32 public constant DISTRIBUTOR_ROLE = keccak256("DISTRIBUTOR_ROLE");

    // Token de pago (USDC)
    IERC20 public paymentToken;

    // Estructura de distribucion
    struct Distribution {
        bytes32 projectId;
        bytes32 merkleRoot;
        uint256 totalAmount;
        uint256 claimedAmount;
        uint256 periodStart;
        uint256 periodEnd;
        uint256 createdAt;
        uint256 expiresAt;
        bool active;
        string description;
    }

    // Almacenamiento
    mapping(uint256 => Distribution) public distributions;
    mapping(uint256 => mapping(address => bool)) public hasClaimed;
    mapping(bytes32 => uint256[]) public projectDistributions;

    uint256 public nextDistributionId;
    uint256 public claimExpirationPeriod;  // Periodo para reclamar despues de distribucion

    // Contadores
    uint256 public totalDistributed;
    uint256 public totalClaimed;

    // Eventos
    event DistributionCreated(
        uint256 indexed distributionId,
        bytes32 indexed projectId,
        bytes32 merkleRoot,
        uint256 totalAmount,
        uint256 expiresAt
    );
    event DividendClaimed(
        uint256 indexed distributionId,
        address indexed account,
        uint256 amount
    );
    event DistributionCancelled(uint256 indexed distributionId);
    event UnclaimedFundsRecovered(uint256 indexed distributionId, uint256 amount);
    event ExpirationPeriodUpdated(uint256 newPeriod);

    /**
     * @dev Constructor
     * @param _paymentToken Token de pago (USDC)
     * @param _claimExpirationDays Dias para reclamar dividendos
     * @param admin Administrador
     */
    constructor(
        address _paymentToken,
        uint256 _claimExpirationDays,
        address admin
    ) {
        require(_paymentToken != address(0), "Invalid payment token");
        require(admin != address(0), "Invalid admin");

        paymentToken = IERC20(_paymentToken);
        claimExpirationPeriod = _claimExpirationDays * 1 days;

        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(DISTRIBUTOR_ROLE, admin);
    }

    // ==================== DISTRIBUTION FUNCTIONS ====================

    /**
     * @dev Crea una nueva distribucion de dividendos
     * @param projectId ID del proyecto
     * @param merkleRoot Raiz del Merkle tree con los reclamos
     * @param totalAmount Monto total a distribuir
     * @param periodStart Inicio del periodo de dividendos
     * @param periodEnd Fin del periodo de dividendos
     * @param description Descripcion de la distribucion
     */
    function createDistribution(
        bytes32 projectId,
        bytes32 merkleRoot,
        uint256 totalAmount,
        uint256 periodStart,
        uint256 periodEnd,
        string calldata description
    ) external onlyRole(DISTRIBUTOR_ROLE) whenNotPaused returns (uint256) {
        require(merkleRoot != bytes32(0), "Invalid merkle root");
        require(totalAmount > 0, "Invalid amount");
        require(periodStart < periodEnd, "Invalid period");

        // Transferir fondos al contrato
        paymentToken.safeTransferFrom(msg.sender, address(this), totalAmount);

        uint256 distributionId = nextDistributionId++;
        uint256 expiresAt = block.timestamp + claimExpirationPeriod;

        distributions[distributionId] = Distribution({
            projectId: projectId,
            merkleRoot: merkleRoot,
            totalAmount: totalAmount,
            claimedAmount: 0,
            periodStart: periodStart,
            periodEnd: periodEnd,
            createdAt: block.timestamp,
            expiresAt: expiresAt,
            active: true,
            description: description
        });

        projectDistributions[projectId].push(distributionId);
        totalDistributed += totalAmount;

        emit DistributionCreated(
            distributionId,
            projectId,
            merkleRoot,
            totalAmount,
            expiresAt
        );

        return distributionId;
    }

    /**
     * @dev Reclama dividendos usando una prueba Merkle
     * @param distributionId ID de la distribucion
     * @param amount Monto a reclamar
     * @param merkleProof Prueba Merkle
     */
    function claimDividend(
        uint256 distributionId,
        uint256 amount,
        bytes32[] calldata merkleProof
    ) external nonReentrant whenNotPaused {
        Distribution storage dist = distributions[distributionId];

        require(dist.active, "Distribution not active");
        require(block.timestamp <= dist.expiresAt, "Distribution expired");
        require(!hasClaimed[distributionId][msg.sender], "Already claimed");
        require(amount > 0, "Invalid amount");

        // Verificar prueba Merkle
        bytes32 leaf = keccak256(
            bytes.concat(keccak256(abi.encode(msg.sender, amount)))
        );
        require(
            MerkleProof.verify(merkleProof, dist.merkleRoot, leaf),
            "Invalid proof"
        );

        // Marcar como reclamado
        hasClaimed[distributionId][msg.sender] = true;
        dist.claimedAmount += amount;
        totalClaimed += amount;

        // Transferir dividendo
        paymentToken.safeTransfer(msg.sender, amount);

        emit DividendClaimed(distributionId, msg.sender, amount);
    }

    /**
     * @dev Reclama multiples dividendos en una transaccion
     * @param distributionIds IDs de las distribuciones
     * @param amounts Montos a reclamar
     * @param merkleProofs Pruebas Merkle (array de arrays)
     */
    function batchClaimDividends(
        uint256[] calldata distributionIds,
        uint256[] calldata amounts,
        bytes32[][] calldata merkleProofs
    ) external nonReentrant whenNotPaused {
        require(
            distributionIds.length == amounts.length &&
            amounts.length == merkleProofs.length,
            "Length mismatch"
        );

        uint256 totalToClaim = 0;

        for (uint256 i = 0; i < distributionIds.length; i++) {
            uint256 distId = distributionIds[i];
            uint256 amount = amounts[i];
            bytes32[] calldata proof = merkleProofs[i];

            Distribution storage dist = distributions[distId];

            if (!dist.active || block.timestamp > dist.expiresAt) {
                continue;
            }

            if (hasClaimed[distId][msg.sender] || amount == 0) {
                continue;
            }

            // Verificar prueba
            bytes32 leaf = keccak256(
                bytes.concat(keccak256(abi.encode(msg.sender, amount)))
            );

            if (!MerkleProof.verify(proof, dist.merkleRoot, leaf)) {
                continue;
            }

            hasClaimed[distId][msg.sender] = true;
            dist.claimedAmount += amount;
            totalClaimed += amount;
            totalToClaim += amount;

            emit DividendClaimed(distId, msg.sender, amount);
        }

        if (totalToClaim > 0) {
            paymentToken.safeTransfer(msg.sender, totalToClaim);
        }
    }

    // ==================== ADMIN FUNCTIONS ====================

    /**
     * @dev Cancela una distribucion activa
     * @param distributionId ID de la distribucion
     */
    function cancelDistribution(
        uint256 distributionId
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        Distribution storage dist = distributions[distributionId];
        require(dist.active, "Not active");

        dist.active = false;

        // Devolver fondos no reclamados
        uint256 unclaimed = dist.totalAmount - dist.claimedAmount;
        if (unclaimed > 0) {
            paymentToken.safeTransfer(msg.sender, unclaimed);
        }

        emit DistributionCancelled(distributionId);
    }

    /**
     * @dev Recupera fondos no reclamados de distribuciones expiradas
     * @param distributionIds IDs de las distribuciones
     */
    function recoverUnclaimedFunds(
        uint256[] calldata distributionIds
    ) external onlyRole(DEFAULT_ADMIN_ROLE) nonReentrant {
        uint256 totalRecovered = 0;

        for (uint256 i = 0; i < distributionIds.length; i++) {
            Distribution storage dist = distributions[distributionIds[i]];

            if (!dist.active || block.timestamp <= dist.expiresAt) {
                continue;
            }

            uint256 unclaimed = dist.totalAmount - dist.claimedAmount;
            if (unclaimed > 0) {
                dist.active = false;
                totalRecovered += unclaimed;
                emit UnclaimedFundsRecovered(distributionIds[i], unclaimed);
            }
        }

        if (totalRecovered > 0) {
            paymentToken.safeTransfer(msg.sender, totalRecovered);
        }
    }

    /**
     * @dev Actualiza el periodo de expiracion para nuevas distribuciones
     * @param newPeriodDays Nuevo periodo en dias
     */
    function setClaimExpirationPeriod(
        uint256 newPeriodDays
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newPeriodDays > 0, "Invalid period");
        claimExpirationPeriod = newPeriodDays * 1 days;
        emit ExpirationPeriodUpdated(claimExpirationPeriod);
    }

    /**
     * @dev Pausa el contrato
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @dev Reanuda el contrato
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    // ==================== VIEW FUNCTIONS ====================

    /**
     * @dev Obtiene informacion de una distribucion
     * @param distributionId ID de la distribucion
     */
    function getDistribution(uint256 distributionId) external view returns (
        bytes32 projectId,
        bytes32 merkleRoot,
        uint256 totalAmount,
        uint256 claimedAmount,
        uint256 periodStart,
        uint256 periodEnd,
        uint256 createdAt,
        uint256 expiresAt,
        bool active
    ) {
        Distribution storage dist = distributions[distributionId];
        return (
            dist.projectId,
            dist.merkleRoot,
            dist.totalAmount,
            dist.claimedAmount,
            dist.periodStart,
            dist.periodEnd,
            dist.createdAt,
            dist.expiresAt,
            dist.active
        );
    }

    /**
     * @dev Verifica si una cuenta puede reclamar dividendos
     * @param distributionId ID de la distribucion
     * @param account Direccion a verificar
     * @param amount Monto esperado
     * @param merkleProof Prueba Merkle
     */
    function canClaim(
        uint256 distributionId,
        address account,
        uint256 amount,
        bytes32[] calldata merkleProof
    ) external view returns (bool) {
        Distribution storage dist = distributions[distributionId];

        if (!dist.active || block.timestamp > dist.expiresAt) {
            return false;
        }

        if (hasClaimed[distributionId][account]) {
            return false;
        }

        bytes32 leaf = keccak256(
            bytes.concat(keccak256(abi.encode(account, amount)))
        );

        return MerkleProof.verify(merkleProof, dist.merkleRoot, leaf);
    }

    /**
     * @dev Obtiene las distribuciones de un proyecto
     * @param projectId ID del proyecto
     */
    function getProjectDistributions(
        bytes32 projectId
    ) external view returns (uint256[] memory) {
        return projectDistributions[projectId];
    }

    /**
     * @dev Obtiene el monto pendiente de una distribucion
     * @param distributionId ID de la distribucion
     */
    function getUnclaimedAmount(uint256 distributionId) external view returns (uint256) {
        Distribution storage dist = distributions[distributionId];
        return dist.totalAmount - dist.claimedAmount;
    }

    /**
     * @dev Obtiene estadisticas generales
     */
    function getStats() external view returns (
        uint256 _totalDistributed,
        uint256 _totalClaimed,
        uint256 _totalPending,
        uint256 _distributionCount
    ) {
        return (
            totalDistributed,
            totalClaimed,
            totalDistributed - totalClaimed,
            nextDistributionId
        );
    }

    /**
     * @dev Obtiene el balance total en el contrato
     */
    function getContractBalance() external view returns (uint256) {
        return paymentToken.balanceOf(address(this));
    }
}

src/FinCoreInvestment.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/**
 * @title FinCoreInvestment
 * @dev Contrato principal de inversiones con escrow.
 * Gestiona depositos, liberaciones y distribucion de dividendos.
 */
contract FinCoreInvestment is AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    bytes32 public constant DIVIDEND_MANAGER_ROLE = keccak256("DIVIDEND_MANAGER_ROLE");

    // Token de pago (USDC)
    IERC20 public paymentToken;
    uint8 public paymentTokenDecimals;

    // Estructura de inversion
    struct Investment {
        bytes32 projectId;
        address investor;
        uint256 amount;
        uint256 tokenAmount;
        uint256 createdAt;
        bool released;
        bool refunded;
    }

    // Estructura de proyecto
    struct Project {
        bytes32 id;
        address tokenContract;
        uint256 targetAmount;
        uint256 raisedAmount;
        uint256 startTime;
        uint256 endTime;
        bool fundingComplete;
        bool fundsReleased;
        ProjectStatus status;
    }

    enum ProjectStatus {
        Draft,
        Active,
        Funded,
        Cancelled,
        Completed
    }

    // Almacenamiento
    mapping(bytes32 => Project) public projects;
    mapping(uint256 => Investment) public investments;
    mapping(bytes32 => uint256[]) public projectInvestments;
    mapping(address => uint256[]) public investorInvestments;
    mapping(bytes32 => mapping(address => uint256)) public investorProjectBalance;

    uint256 public nextInvestmentId;

    // Fees
    uint256 public platformFeePercent;  // En basis points (100 = 1%)
    address public feeRecipient;

    // Limites
    uint256 public minInvestmentAmount;
    uint256 public maxInvestmentAmount;

    // Eventos
    event ProjectCreated(bytes32 indexed projectId, address tokenContract, uint256 targetAmount);
    event ProjectStatusUpdated(bytes32 indexed projectId, ProjectStatus status);
    event InvestmentCreated(
        uint256 indexed investmentId,
        bytes32 indexed projectId,
        address indexed investor,
        uint256 amount,
        uint256 tokenAmount
    );
    event InvestmentReleased(uint256 indexed investmentId, bytes32 indexed projectId);
    event InvestmentRefunded(uint256 indexed investmentId, address indexed investor, uint256 amount);
    event FundsReleased(bytes32 indexed projectId, address recipient, uint256 amount);
    event DividendDistributed(bytes32 indexed projectId, uint256 totalAmount, uint256 holdersCount);
    event FeeUpdated(uint256 newFeePercent);
    event PaymentTokenUpdated(address newToken);

    /**
     * @dev Constructor
     * @param _paymentToken Direccion del token de pago (USDC)
     * @param _paymentTokenDecimals Decimales del token de pago
     * @param _feeRecipient Direccion que recibe los fees
     * @param _admin Administrador del contrato
     */
    constructor(
        address _paymentToken,
        uint8 _paymentTokenDecimals,
        address _feeRecipient,
        address _admin
    ) {
        require(_paymentToken != address(0), "Invalid payment token");
        require(_feeRecipient != address(0), "Invalid fee recipient");
        require(_admin != address(0), "Invalid admin");

        paymentToken = IERC20(_paymentToken);
        paymentTokenDecimals = _paymentTokenDecimals;
        feeRecipient = _feeRecipient;

        platformFeePercent = 100; // 1%
        minInvestmentAmount = 100 * 10**_paymentTokenDecimals; // 100 USDC
        maxInvestmentAmount = 1000000 * 10**_paymentTokenDecimals; // 1M USDC

        _grantRole(DEFAULT_ADMIN_ROLE, _admin);
        _grantRole(OPERATOR_ROLE, _admin);
        _grantRole(DIVIDEND_MANAGER_ROLE, _admin);
    }

    // ==================== PROJECT MANAGEMENT ====================

    /**
     * @dev Crea un nuevo proyecto
     * @param projectId ID unico del proyecto
     * @param tokenContract Direccion del contrato del token del proyecto
     * @param targetAmount Monto objetivo de recaudacion
     * @param startTime Inicio del periodo de inversion
     * @param endTime Fin del periodo de inversion
     */
    function createProject(
        bytes32 projectId,
        address tokenContract,
        uint256 targetAmount,
        uint256 startTime,
        uint256 endTime
    ) external onlyRole(OPERATOR_ROLE) {
        require(projects[projectId].id == bytes32(0), "Project already exists");
        require(tokenContract != address(0), "Invalid token contract");
        require(targetAmount > 0, "Target must be positive");
        require(startTime >= block.timestamp, "Start time must be in future");
        require(endTime > startTime, "End must be after start");

        projects[projectId] = Project({
            id: projectId,
            tokenContract: tokenContract,
            targetAmount: targetAmount,
            raisedAmount: 0,
            startTime: startTime,
            endTime: endTime,
            fundingComplete: false,
            fundsReleased: false,
            status: ProjectStatus.Draft
        });

        emit ProjectCreated(projectId, tokenContract, targetAmount);
    }

    /**
     * @dev Activa un proyecto para recibir inversiones
     * @param projectId ID del proyecto
     */
    function activateProject(bytes32 projectId) external onlyRole(OPERATOR_ROLE) {
        Project storage project = projects[projectId];
        require(project.id != bytes32(0), "Project not found");
        require(project.status == ProjectStatus.Draft, "Project not in draft");

        project.status = ProjectStatus.Active;
        emit ProjectStatusUpdated(projectId, ProjectStatus.Active);
    }

    /**
     * @dev Cancela un proyecto y permite reembolsos
     * @param projectId ID del proyecto
     */
    function cancelProject(bytes32 projectId) external onlyRole(OPERATOR_ROLE) {
        Project storage project = projects[projectId];
        require(project.id != bytes32(0), "Project not found");
        require(
            project.status == ProjectStatus.Draft || project.status == ProjectStatus.Active,
            "Cannot cancel"
        );
        require(!project.fundsReleased, "Funds already released");

        project.status = ProjectStatus.Cancelled;
        emit ProjectStatusUpdated(projectId, ProjectStatus.Cancelled);
    }

    // ==================== INVESTMENT OPERATIONS ====================

    /**
     * @dev Realiza una inversion en un proyecto
     * @param projectId ID del proyecto
     * @param amount Monto a invertir
     * @param tokenAmount Cantidad de tokens a recibir
     */
    function invest(
        bytes32 projectId,
        uint256 amount,
        uint256 tokenAmount
    ) external nonReentrant whenNotPaused {
        Project storage project = projects[projectId];

        require(project.id != bytes32(0), "Project not found");
        require(project.status == ProjectStatus.Active, "Project not active");
        require(block.timestamp >= project.startTime, "Funding not started");
        require(block.timestamp <= project.endTime, "Funding ended");
        require(amount >= minInvestmentAmount, "Below minimum investment");
        require(amount <= maxInvestmentAmount, "Above maximum investment");
        require(project.raisedAmount + amount <= project.targetAmount, "Exceeds target");

        // Transferir tokens del inversor al contrato (escrow)
        paymentToken.safeTransferFrom(msg.sender, address(this), amount);

        // Crear registro de inversion
        uint256 investmentId = nextInvestmentId++;
        investments[investmentId] = Investment({
            projectId: projectId,
            investor: msg.sender,
            amount: amount,
            tokenAmount: tokenAmount,
            createdAt: block.timestamp,
            released: false,
            refunded: false
        });

        // Actualizar indices
        projectInvestments[projectId].push(investmentId);
        investorInvestments[msg.sender].push(investmentId);
        investorProjectBalance[projectId][msg.sender] += amount;

        // Actualizar monto recaudado
        project.raisedAmount += amount;

        // Verificar si se completo el funding
        if (project.raisedAmount >= project.targetAmount) {
            project.fundingComplete = true;
            project.status = ProjectStatus.Funded;
            emit ProjectStatusUpdated(projectId, ProjectStatus.Funded);
        }

        emit InvestmentCreated(investmentId, projectId, msg.sender, amount, tokenAmount);
    }

    /**
     * @dev Libera los fondos de un proyecto al beneficiario
     * @param projectId ID del proyecto
     * @param recipient Direccion que recibe los fondos
     */
    function releaseFunds(
        bytes32 projectId,
        address recipient
    ) external onlyRole(OPERATOR_ROLE) nonReentrant {
        Project storage project = projects[projectId];

        require(project.id != bytes32(0), "Project not found");
        require(project.status == ProjectStatus.Funded, "Not funded");
        require(!project.fundsReleased, "Already released");
        require(recipient != address(0), "Invalid recipient");

        uint256 totalAmount = project.raisedAmount;
        uint256 fee = (totalAmount * platformFeePercent) / 10000;
        uint256 netAmount = totalAmount - fee;

        project.fundsReleased = true;
        project.status = ProjectStatus.Completed;

        // Marcar inversiones como liberadas
        uint256[] storage invIds = projectInvestments[projectId];
        for (uint256 i = 0; i < invIds.length; i++) {
            investments[invIds[i]].released = true;
            emit InvestmentReleased(invIds[i], projectId);
        }

        // Transferir fondos
        if (fee > 0) {
            paymentToken.safeTransfer(feeRecipient, fee);
        }
        paymentToken.safeTransfer(recipient, netAmount);

        emit FundsReleased(projectId, recipient, netAmount);
        emit ProjectStatusUpdated(projectId, ProjectStatus.Completed);
    }

    /**
     * @dev Reembolsa una inversion (solo si el proyecto fue cancelado)
     * @param investmentId ID de la inversion
     */
    function refundInvestment(uint256 investmentId) external nonReentrant {
        Investment storage investment = investments[investmentId];

        require(investment.investor == msg.sender, "Not your investment");
        require(!investment.released, "Already released");
        require(!investment.refunded, "Already refunded");

        Project storage project = projects[investment.projectId];
        require(
            project.status == ProjectStatus.Cancelled ||
            (project.status == ProjectStatus.Active && block.timestamp > project.endTime && !project.fundingComplete),
            "Refund not available"
        );

        investment.refunded = true;
        investorProjectBalance[investment.projectId][msg.sender] -= investment.amount;

        paymentToken.safeTransfer(msg.sender, investment.amount);

        emit InvestmentRefunded(investmentId, msg.sender, investment.amount);
    }

    // ==================== DIVIDEND DISTRIBUTION ====================

    /**
     * @dev Distribuye dividendos a los holders de un proyecto
     * @param projectId ID del proyecto
     * @param totalAmount Monto total a distribuir
     * @param holders Lista de direcciones de holders
     * @param amounts Lista de montos para cada holder
     */
    function distributeDividends(
        bytes32 projectId,
        uint256 totalAmount,
        address[] calldata holders,
        uint256[] calldata amounts
    ) external onlyRole(DIVIDEND_MANAGER_ROLE) nonReentrant {
        require(holders.length == amounts.length, "Length mismatch");
        require(holders.length > 0, "No holders");

        Project storage project = projects[projectId];
        require(project.id != bytes32(0), "Project not found");
        require(project.status == ProjectStatus.Completed, "Project not completed");

        // Verificar que el total coincide
        uint256 sum = 0;
        for (uint256 i = 0; i < amounts.length; i++) {
            sum += amounts[i];
        }
        require(sum == totalAmount, "Amount mismatch");

        // Transferir desde el caller al contrato
        paymentToken.safeTransferFrom(msg.sender, address(this), totalAmount);

        // Distribuir a cada holder
        for (uint256 i = 0; i < holders.length; i++) {
            if (amounts[i] > 0) {
                paymentToken.safeTransfer(holders[i], amounts[i]);
            }
        }

        emit DividendDistributed(projectId, totalAmount, holders.length);
    }

    // ==================== ADMIN FUNCTIONS ====================

    /**
     * @dev Actualiza el fee de la plataforma
     * @param newFeePercent Nuevo fee en basis points
     */
    function setFee(uint256 newFeePercent) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newFeePercent <= 1000, "Fee too high"); // Max 10%
        platformFeePercent = newFeePercent;
        emit FeeUpdated(newFeePercent);
    }

    /**
     * @dev Actualiza el token de pago
     * @param newToken Direccion del nuevo token
     * @param decimals Decimales del token
     */
    function setPaymentToken(address newToken, uint8 decimals) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newToken != address(0), "Invalid token");
        paymentToken = IERC20(newToken);
        paymentTokenDecimals = decimals;
        emit PaymentTokenUpdated(newToken);
    }

    /**
     * @dev Actualiza los limites de inversion
     * @param minAmount Minimo
     * @param maxAmount Maximo
     */
    function setInvestmentLimits(
        uint256 minAmount,
        uint256 maxAmount
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(minAmount < maxAmount, "Invalid limits");
        minInvestmentAmount = minAmount;
        maxInvestmentAmount = maxAmount;
    }

    /**
     * @dev Actualiza el receptor de fees
     * @param newRecipient Nueva direccion
     */
    function setFeeRecipient(address newRecipient) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newRecipient != address(0), "Invalid recipient");
        feeRecipient = newRecipient;
    }

    /**
     * @dev Pausa el contrato
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @dev Reanuda el contrato
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    // ==================== VIEW FUNCTIONS ====================

    /**
     * @dev Obtiene informacion de un proyecto
     * @param projectId ID del proyecto
     */
    function getProject(bytes32 projectId) external view returns (
        address tokenContract,
        uint256 targetAmount,
        uint256 raisedAmount,
        uint256 startTime,
        uint256 endTime,
        bool fundingComplete,
        bool fundsReleased,
        ProjectStatus status
    ) {
        Project storage p = projects[projectId];
        return (
            p.tokenContract,
            p.targetAmount,
            p.raisedAmount,
            p.startTime,
            p.endTime,
            p.fundingComplete,
            p.fundsReleased,
            p.status
        );
    }

    /**
     * @dev Obtiene inversiones de un proyecto
     * @param projectId ID del proyecto
     */
    function getProjectInvestments(bytes32 projectId) external view returns (uint256[] memory) {
        return projectInvestments[projectId];
    }

    /**
     * @dev Obtiene inversiones de un inversor
     * @param investor Direccion del inversor
     */
    function getInvestorInvestments(address investor) external view returns (uint256[] memory) {
        return investorInvestments[investor];
    }

    /**
     * @dev Obtiene el balance total en escrow
     */
    function getEscrowBalance() external view returns (uint256) {
        return paymentToken.balanceOf(address(this));
    }
}

src/FinCoreKYC.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title FinCoreKYC
 * @dev Contrato de verificacion KYC on-chain.
 * Almacena hashes de verificacion KYC sin datos personales.
 * Permite verificar que un usuario ha pasado KYC sin exponer informacion sensible.
 */
contract FinCoreKYC is AccessControl, Pausable {
    bytes32 public constant VERIFIER_ROLE = keccak256("VERIFIER_ROLE");
    bytes32 public constant REVOKER_ROLE = keccak256("REVOKER_ROLE");

    // Niveles de verificacion KYC
    enum KYCLevel {
        None,       // Sin verificacion
        Basic,      // Email + telefono verificado
        Standard,   // Documento de identidad verificado
        Enhanced    // Verificacion completa con prueba de direccion
    }

    // Registro KYC
    struct KYCRecord {
        bytes32 kycHash;           // Hash de los datos KYC
        KYCLevel level;            // Nivel de verificacion
        uint256 verifiedAt;        // Timestamp de verificacion
        uint256 expiresAt;         // Timestamp de expiracion
        address verifier;          // Quien verifico
        bool revoked;              // Si fue revocado
        string revokeReason;       // Razon de revocacion
    }

    // Almacenamiento
    mapping(address => KYCRecord) public kycRecords;
    mapping(bytes32 => address) public hashToAddress;  // Para buscar por hash

    // Configuracion
    uint256 public defaultValidityPeriod;  // Periodo de validez en segundos
    mapping(KYCLevel => uint256) public levelValidityPeriods;

    // Contadores
    uint256 public totalVerified;
    uint256 public totalRevoked;

    // Eventos
    event KYCVerified(
        address indexed account,
        bytes32 indexed kycHash,
        KYCLevel level,
        address verifier,
        uint256 expiresAt
    );
    event KYCRevoked(
        address indexed account,
        bytes32 indexed kycHash,
        address revoker,
        string reason
    );
    event KYCRenewed(
        address indexed account,
        bytes32 indexed kycHash,
        uint256 newExpiresAt
    );
    event KYCLevelUpgraded(
        address indexed account,
        KYCLevel oldLevel,
        KYCLevel newLevel
    );
    event ValidityPeriodUpdated(KYCLevel level, uint256 period);

    /**
     * @dev Constructor
     * @param admin Administrador del contrato
     * @param _defaultValidityPeriod Periodo de validez por defecto en dias
     */
    constructor(address admin, uint256 _defaultValidityPeriod) {
        require(admin != address(0), "Invalid admin");
        require(_defaultValidityPeriod > 0, "Invalid validity period");

        defaultValidityPeriod = _defaultValidityPeriod * 1 days;

        // Periodos por defecto por nivel
        levelValidityPeriods[KYCLevel.Basic] = 90 days;
        levelValidityPeriods[KYCLevel.Standard] = 365 days;
        levelValidityPeriods[KYCLevel.Enhanced] = 730 days; // 2 anios

        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(VERIFIER_ROLE, admin);
        _grantRole(REVOKER_ROLE, admin);
    }

    // ==================== VERIFICATION FUNCTIONS ====================

    /**
     * @dev Registra una verificacion KYC
     * @param account Direccion del usuario
     * @param kycHash Hash de los datos KYC
     * @param level Nivel de verificacion
     */
    function verifyKYC(
        address account,
        bytes32 kycHash,
        KYCLevel level
    ) external onlyRole(VERIFIER_ROLE) whenNotPaused {
        require(account != address(0), "Invalid account");
        require(kycHash != bytes32(0), "Invalid KYC hash");
        require(level != KYCLevel.None, "Invalid level");
        require(hashToAddress[kycHash] == address(0), "Hash already used");

        // Verificar si ya tiene un registro anterior
        KYCRecord storage existingRecord = kycRecords[account];
        if (existingRecord.kycHash != bytes32(0) && !existingRecord.revoked) {
            // Limpiar hash anterior
            delete hashToAddress[existingRecord.kycHash];
        }

        // Calcular expiracion
        uint256 validity = levelValidityPeriods[level];
        if (validity == 0) {
            validity = defaultValidityPeriod;
        }
        uint256 expiresAt = block.timestamp + validity;

        // Crear registro
        kycRecords[account] = KYCRecord({
            kycHash: kycHash,
            level: level,
            verifiedAt: block.timestamp,
            expiresAt: expiresAt,
            verifier: msg.sender,
            revoked: false,
            revokeReason: ""
        });

        hashToAddress[kycHash] = account;
        totalVerified++;

        emit KYCVerified(account, kycHash, level, msg.sender, expiresAt);
    }

    /**
     * @dev Registra multiples verificaciones KYC en batch
     * @param accounts Lista de direcciones
     * @param kycHashes Lista de hashes
     * @param levels Lista de niveles
     */
    function batchVerifyKYC(
        address[] calldata accounts,
        bytes32[] calldata kycHashes,
        KYCLevel[] calldata levels
    ) external onlyRole(VERIFIER_ROLE) whenNotPaused {
        require(
            accounts.length == kycHashes.length && kycHashes.length == levels.length,
            "Length mismatch"
        );

        for (uint256 i = 0; i < accounts.length; i++) {
            address account = accounts[i];
            bytes32 kycHash = kycHashes[i];
            KYCLevel level = levels[i];

            if (account == address(0) || kycHash == bytes32(0) || level == KYCLevel.None) {
                continue;
            }

            if (hashToAddress[kycHash] != address(0)) {
                continue;
            }

            // Limpiar registro anterior si existe
            KYCRecord storage existingRecord = kycRecords[account];
            if (existingRecord.kycHash != bytes32(0) && !existingRecord.revoked) {
                delete hashToAddress[existingRecord.kycHash];
            }

            uint256 validity = levelValidityPeriods[level];
            if (validity == 0) {
                validity = defaultValidityPeriod;
            }
            uint256 expiresAt = block.timestamp + validity;

            kycRecords[account] = KYCRecord({
                kycHash: kycHash,
                level: level,
                verifiedAt: block.timestamp,
                expiresAt: expiresAt,
                verifier: msg.sender,
                revoked: false,
                revokeReason: ""
            });

            hashToAddress[kycHash] = account;
            totalVerified++;

            emit KYCVerified(account, kycHash, level, msg.sender, expiresAt);
        }
    }

    /**
     * @dev Revoca una verificacion KYC
     * @param account Direccion del usuario
     * @param reason Razon de la revocacion
     */
    function revokeKYC(
        address account,
        string calldata reason
    ) external onlyRole(REVOKER_ROLE) {
        KYCRecord storage record = kycRecords[account];
        require(record.kycHash != bytes32(0), "No KYC record");
        require(!record.revoked, "Already revoked");

        record.revoked = true;
        record.revokeReason = reason;
        totalRevoked++;

        emit KYCRevoked(account, record.kycHash, msg.sender, reason);
    }

    /**
     * @dev Renueva una verificacion KYC existente
     * @param account Direccion del usuario
     * @param additionalTime Tiempo adicional en segundos
     */
    function renewKYC(
        address account,
        uint256 additionalTime
    ) external onlyRole(VERIFIER_ROLE) whenNotPaused {
        KYCRecord storage record = kycRecords[account];
        require(record.kycHash != bytes32(0), "No KYC record");
        require(!record.revoked, "KYC revoked");

        // Extender desde ahora o desde la expiracion actual, lo que sea mayor
        uint256 baseTime = record.expiresAt > block.timestamp
            ? record.expiresAt
            : block.timestamp;

        record.expiresAt = baseTime + additionalTime;

        emit KYCRenewed(account, record.kycHash, record.expiresAt);
    }

    /**
     * @dev Actualiza el nivel de KYC de un usuario
     * @param account Direccion del usuario
     * @param newLevel Nuevo nivel
     */
    function upgradeKYCLevel(
        address account,
        KYCLevel newLevel
    ) external onlyRole(VERIFIER_ROLE) whenNotPaused {
        KYCRecord storage record = kycRecords[account];
        require(record.kycHash != bytes32(0), "No KYC record");
        require(!record.revoked, "KYC revoked");
        require(newLevel > record.level, "Can only upgrade");

        KYCLevel oldLevel = record.level;
        record.level = newLevel;

        // Extender validez segun nuevo nivel
        uint256 validity = levelValidityPeriods[newLevel];
        if (validity == 0) {
            validity = defaultValidityPeriod;
        }
        record.expiresAt = block.timestamp + validity;

        emit KYCLevelUpgraded(account, oldLevel, newLevel);
    }

    // ==================== VIEW FUNCTIONS ====================

    /**
     * @dev Verifica si una cuenta tiene KYC valido
     * @param account Direccion a verificar
     */
    function isKYCValid(address account) external view returns (bool) {
        KYCRecord storage record = kycRecords[account];
        return record.kycHash != bytes32(0) &&
               !record.revoked &&
               record.expiresAt > block.timestamp;
    }

    /**
     * @dev Verifica si una cuenta tiene un nivel minimo de KYC
     * @param account Direccion a verificar
     * @param minLevel Nivel minimo requerido
     */
    function hasMinimumKYCLevel(
        address account,
        KYCLevel minLevel
    ) external view returns (bool) {
        KYCRecord storage record = kycRecords[account];
        return record.kycHash != bytes32(0) &&
               !record.revoked &&
               record.expiresAt > block.timestamp &&
               record.level >= minLevel;
    }

    /**
     * @dev Obtiene el registro KYC completo de una cuenta
     * @param account Direccion a consultar
     */
    function getKYCRecord(address account) external view returns (
        bytes32 kycHash,
        KYCLevel level,
        uint256 verifiedAt,
        uint256 expiresAt,
        address verifier,
        bool revoked,
        string memory revokeReason
    ) {
        KYCRecord storage record = kycRecords[account];
        return (
            record.kycHash,
            record.level,
            record.verifiedAt,
            record.expiresAt,
            record.verifier,
            record.revoked,
            record.revokeReason
        );
    }

    /**
     * @dev Verifica si un hash KYC especifico es valido para una cuenta
     * @param account Direccion del usuario
     * @param kycHash Hash a verificar
     */
    function verifyKYCHash(
        address account,
        bytes32 kycHash
    ) external view returns (bool) {
        KYCRecord storage record = kycRecords[account];
        return record.kycHash == kycHash &&
               !record.revoked &&
               record.expiresAt > block.timestamp;
    }

    /**
     * @dev Obtiene la direccion asociada a un hash KYC
     * @param kycHash Hash a buscar
     */
    function getAddressForHash(bytes32 kycHash) external view returns (address) {
        return hashToAddress[kycHash];
    }

    /**
     * @dev Obtiene estadisticas generales
     */
    function getStats() external view returns (
        uint256 _totalVerified,
        uint256 _totalRevoked,
        uint256 _activeCount
    ) {
        return (totalVerified, totalRevoked, totalVerified - totalRevoked);
    }

    // ==================== ADMIN FUNCTIONS ====================

    /**
     * @dev Actualiza el periodo de validez para un nivel
     * @param level Nivel de KYC
     * @param period Periodo en segundos
     */
    function setValidityPeriod(
        KYCLevel level,
        uint256 period
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(level != KYCLevel.None, "Invalid level");
        require(period > 0, "Invalid period");
        levelValidityPeriods[level] = period;
        emit ValidityPeriodUpdated(level, period);
    }

    /**
     * @dev Actualiza el periodo de validez por defecto
     * @param period Periodo en dias
     */
    function setDefaultValidityPeriod(uint256 period) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(period > 0, "Invalid period");
        defaultValidityPeriod = period * 1 days;
    }

    /**
     * @dev Pausa el contrato
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @dev Reanuda el contrato
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

src/FinCoreProjectToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Pausable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title FinCoreProjectToken
 * @dev Token ERC-20 que representa fracciones de un proyecto de inversion.
 * Implementa controles de acceso, pausabilidad y capacidad de quemar tokens.
 */
contract FinCoreProjectToken is ERC20, ERC20Burnable, ERC20Pausable, AccessControl, ReentrancyGuard {
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");
    bytes32 public constant TRANSFER_AGENT_ROLE = keccak256("TRANSFER_AGENT_ROLE");

    // Informacion del proyecto
    bytes32 public projectId;
    uint256 public projectValuation;
    uint256 public totalTokensForSale;
    uint256 public tokensSold;
    uint256 public pricePerToken;  // En USDC (6 decimales)

    // Configuracion de transferencias
    bool public transfersEnabled;
    bool public kycRequired;
    mapping(address => bool) public kycApproved;

    // Limites de inversion
    uint256 public minInvestmentTokens;
    uint256 public maxInvestmentPerWallet;
    mapping(address => uint256) public walletInvestments;

    // Vesting
    mapping(address => uint256) public lockedUntil;

    // Eventos
    event TokensPurchased(address indexed buyer, uint256 amount, uint256 totalPaid);
    event KYCStatusUpdated(address indexed account, bool approved);
    event TransfersToggled(bool enabled);
    event ProjectValuationUpdated(uint256 newValuation);
    event TokensLocked(address indexed account, uint256 until);
    event TokensUnlocked(address indexed account);

    /**
     * @dev Constructor del token del proyecto
     * @param name_ Nombre del token (ej: "FinCore Project 001")
     * @param symbol_ Simbolo del token (ej: "FCP001")
     * @param projectId_ ID interno del proyecto (hash)
     * @param totalSupply_ Total de tokens a crear
     * @param pricePerToken_ Precio por token en USDC (6 decimales)
     * @param admin Direccion del administrador
     */
    constructor(
        string memory name_,
        string memory symbol_,
        bytes32 projectId_,
        uint256 totalSupply_,
        uint256 pricePerToken_,
        address admin
    ) ERC20(name_, symbol_) {
        require(admin != address(0), "Invalid admin address");
        require(totalSupply_ > 0, "Total supply must be positive");
        require(pricePerToken_ > 0, "Price must be positive");

        projectId = projectId_;
        totalTokensForSale = totalSupply_;
        pricePerToken = pricePerToken_;
        projectValuation = totalSupply_ * pricePerToken_;

        // Configuracion por defecto
        transfersEnabled = false;  // Deshabilitadas hasta que termine la venta
        kycRequired = true;
        minInvestmentTokens = 1 * 10**decimals();  // Minimo 1 token
        maxInvestmentPerWallet = totalSupply_ / 10;  // Maximo 10% por wallet

        // Roles
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(MINTER_ROLE, admin);
        _grantRole(PAUSER_ROLE, admin);
        _grantRole(TRANSFER_AGENT_ROLE, admin);
    }

    /**
     * @dev Compra tokens del proyecto
     * @param amount Cantidad de tokens a comprar
     */
    function purchaseTokens(uint256 amount) external nonReentrant whenNotPaused {
        require(amount >= minInvestmentTokens, "Below minimum investment");
        require(tokensSold + amount <= totalTokensForSale, "Not enough tokens available");
        require(
            walletInvestments[msg.sender] + amount <= maxInvestmentPerWallet,
            "Exceeds max investment per wallet"
        );

        if (kycRequired) {
            require(kycApproved[msg.sender], "KYC not approved");
        }

        uint256 totalCost = (amount * pricePerToken) / 10**decimals();

        // Actualizar estado
        tokensSold += amount;
        walletInvestments[msg.sender] += amount;

        // Mintear tokens al comprador
        _mint(msg.sender, amount);

        emit TokensPurchased(msg.sender, amount, totalCost);
    }

    /**
     * @dev Mintea tokens (solo para roles autorizados)
     * @param to Direccion destino
     * @param amount Cantidad de tokens
     */
    function mint(address to, uint256 amount) external onlyRole(MINTER_ROLE) {
        require(to != address(0), "Cannot mint to zero address");
        _mint(to, amount);
    }

    /**
     * @dev Actualiza el estado KYC de una cuenta
     * @param account Direccion de la cuenta
     * @param approved Estado de aprobacion
     */
    function setKYCStatus(address account, bool approved) external onlyRole(TRANSFER_AGENT_ROLE) {
        kycApproved[account] = approved;
        emit KYCStatusUpdated(account, approved);
    }

    /**
     * @dev Actualiza el estado KYC de multiples cuentas
     * @param accounts Lista de direcciones
     * @param approved Estado de aprobacion
     */
    function batchSetKYCStatus(address[] calldata accounts, bool approved) external onlyRole(TRANSFER_AGENT_ROLE) {
        for (uint256 i = 0; i < accounts.length; i++) {
            kycApproved[accounts[i]] = approved;
            emit KYCStatusUpdated(accounts[i], approved);
        }
    }

    /**
     * @dev Habilita o deshabilita transferencias
     * @param enabled Nuevo estado
     */
    function toggleTransfers(bool enabled) external onlyRole(DEFAULT_ADMIN_ROLE) {
        transfersEnabled = enabled;
        emit TransfersToggled(enabled);
    }

    /**
     * @dev Actualiza la valuacion del proyecto
     * @param newValuation Nueva valuacion total
     */
    function updateProjectValuation(uint256 newValuation) external onlyRole(DEFAULT_ADMIN_ROLE) {
        projectValuation = newValuation;
        pricePerToken = newValuation / totalSupply();
        emit ProjectValuationUpdated(newValuation);
    }

    /**
     * @dev Bloquea tokens hasta una fecha
     * @param account Direccion a bloquear
     * @param until Timestamp hasta cuando estan bloqueados
     */
    function lockTokens(address account, uint256 until) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(until > block.timestamp, "Lock time must be in future");
        lockedUntil[account] = until;
        emit TokensLocked(account, until);
    }

    /**
     * @dev Desbloquea tokens de una cuenta
     * @param account Direccion a desbloquear
     */
    function unlockTokens(address account) external onlyRole(DEFAULT_ADMIN_ROLE) {
        lockedUntil[account] = 0;
        emit TokensUnlocked(account);
    }

    /**
     * @dev Pausa el contrato
     */
    function pause() external onlyRole(PAUSER_ROLE) {
        _pause();
    }

    /**
     * @dev Reanuda el contrato
     */
    function unpause() external onlyRole(PAUSER_ROLE) {
        _unpause();
    }

    /**
     * @dev Actualiza limites de inversion
     * @param minTokens Minimo de tokens por compra
     * @param maxPerWallet Maximo de tokens por wallet
     */
    function updateInvestmentLimits(
        uint256 minTokens,
        uint256 maxPerWallet
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        minInvestmentTokens = minTokens;
        maxInvestmentPerWallet = maxPerWallet;
    }

    /**
     * @dev Obtiene informacion del proyecto
     */
    function getProjectInfo() external view returns (
        bytes32 _projectId,
        uint256 _valuation,
        uint256 _totalForSale,
        uint256 _sold,
        uint256 _price,
        bool _transfersEnabled
    ) {
        return (
            projectId,
            projectValuation,
            totalTokensForSale,
            tokensSold,
            pricePerToken,
            transfersEnabled
        );
    }

    /**
     * @dev Balance disponible (no bloqueado) de una cuenta
     * @param account Direccion a consultar
     */
    function availableBalance(address account) external view returns (uint256) {
        if (block.timestamp < lockedUntil[account]) {
            return 0;
        }
        return balanceOf(account);
    }

    // ==================== OVERRIDES ====================

    /**
     * @dev Hook que se ejecuta antes de cada transferencia
     */
    function _update(
        address from,
        address to,
        uint256 amount
    ) internal virtual override(ERC20, ERC20Pausable) {
        // Permitir mint y burn siempre
        if (from != address(0) && to != address(0)) {
            // Verificar si las transferencias estan habilitadas
            require(
                transfersEnabled ||
                hasRole(TRANSFER_AGENT_ROLE, msg.sender),
                "Transfers not enabled"
            );

            // Verificar KYC si es requerido
            if (kycRequired) {
                require(kycApproved[to], "Recipient KYC not approved");
            }

            // Verificar bloqueo
            require(
                block.timestamp >= lockedUntil[from],
                "Tokens are locked"
            );
        }

        super._update(from, to, amount);
    }

    /**
     * @dev Verifica soporte de interfaces
     */
    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(AccessControl)
        returns (bool)
    {
        return super.supportsInterface(interfaceId);
    }
}

